# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, session, redirect, url_for, abort
from flask_oidc import OpenIDConnect, UserManager
import jwt
from datetime import datetime, timedelta

app = Flask(__name__)
oidc = OpenIDConnect(app)
user_manager = UserManager(app)

config_oids = {
    'client_id': '<Your client ID>',
    'client_secret': '<Your client secret>',
    'openid_issuer': '<Your provider issuer URL>',
}

oidc.register(config_oids)

@app.route('/')
def index():
    if not user_manager.is_logged_in:
        return redirect(url_for('login'))
    claims = jwt.decode(user_manager.get_raw_access_token().access_token, audience=config_oids['openid_issuer'], algorithms=['RS256'])
    session['user'] = {k: v for k, v in claims['sub'].items()}  # Store user information in session
    return "Welcome, {}\n".format(session['user']['name'])

@app.route('/login')
def login():
    authorization_endpoint = oidc.blueprint.url_for('authorize')
    return redirect(authorization_endpoint)

@app.route('/callback')
def callback():
    if user_manager.needs_approval and user_manager.authorization_pending:
        user_manager.authorize_access_grant()
    access_token = user_manager.get_raw_access_token()
    id_token = access_token.id_token
    claims = jwt.decode(id_token, audience=config_oids['openid_issuer'], algorithms=['RS256'])
    if not user_manager.validate_id_token(id_token):
        abort(401)  # unauthorized
    session['user'] = {k: v for k, v in claims['sub'].items()}
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.secret_key = '<Your secret key>'
    app.run()